diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..d7d14860c8b8 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1317,6 +1317,7 @@ static Value *foldAndOrOfICmpsWithConstEq(ICmpInst *Cmp0, ICmpInst *Cmp1,
 /// or   (icmp Pred1 V1, C1) | (icmp Pred2 V2, C2)
 /// into a single comparison using range-based reasoning.
 /// NOTE: This is also used for logical and/or, must be poison-safe!
+
 Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
                                                      ICmpInst *ICmp2,
                                                      bool IsAnd) {
@@ -1327,32 +1328,77 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       !match(ICmp2, m_ICmp(Pred2, m_Value(V2), m_APInt(C2))))
     return nullptr;

-  // Look through add of a constant offset on V1, V2, or both operands. This
-  // allows us to interpret the V + C' < C'' range idiom into a proper range.
-  const APInt *Offset1 = nullptr, *Offset2 = nullptr;
-  if (V1 != V2) {
+  auto getRangeForICmp = [&](CmpPredicate Pred, Value *V, const APInt &C,
+                             Value *&BaseV, ConstantRange &CR,
+                             const APInt *&Offset) -> bool {
+    Offset = nullptr;
+    BaseV = V;
+
+    // Look through add of a constant offset. This allows us to interpret the
+    // V + C' < C'' range idiom into a proper range.
     Value *X;
-    if (match(V1, m_Add(m_Value(X), m_APInt(Offset1))))
-      V1 = X;
-    if (match(V2, m_Add(m_Value(X), m_APInt(Offset2))))
-      V2 = X;
-  }
+    if (match(BaseV, m_Add(m_Value(X), m_APInt(Offset))))
+      BaseV = X;

-  if (V1 != V2)
-    return nullptr;
+    CR = ConstantRange::makeExactICmpRegion(
+        IsAnd ? ICmpInst::getInverseCmpPredicate(Pred) : Pred, C);
+    if (Offset)
+      CR = CR.subtract(*Offset);
+    return true;
+  };

-  ConstantRange CR1 = ConstantRange::makeExactICmpRegion(
-      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
-  if (Offset1)
-    CR1 = CR1.subtract(*Offset1);
+  auto getRangeForMaskedICmp = [&](CmpPredicate Pred, Value *V, const APInt &C,
+                                   Value *&BaseV, ConstantRange &CR) -> bool {
+    Value *X;
+    const APInt *Mask;
+    if (!match(V, m_And(m_Value(X), m_APInt(Mask))))
+      return false;
+
+    if (Pred != ICmpInst::ICMP_EQ && Pred != ICmpInst::ICMP_NE)
+      return false;

-  ConstantRange CR2 = ConstantRange::makeExactICmpRegion(
-      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
-  if (Offset2)
-    CR2 = CR2.subtract(*Offset2);
+    unsigned BW = Mask->getBitWidth();
+    unsigned LowZeros = Mask->countr_zero();

-  Type *Ty = V1->getType();
-  Value *NewV = V1;
+    // Recognize masks of the form ~((1 << LowZeros) - 1), i.e. preserve all
+    // high bits and clear a contiguous suffix of low bits.
+    APInt ExpectedMask = APInt::getBitsSetFrom(BW, LowZeros);
+    if (*Mask != ExpectedMask)
+      return false;
+
+    // The compared constant must be aligned to the masked range size.
+    APInt LowMask = APInt::getLowBitsSet(BW, LowZeros);
+    if ((C & LowMask) != 0)
+      return false;
+
+    BaseV = X;
+    ConstantRange EqCR(C, C + APInt(BW, 1).shl(LowZeros));
+
+    if (Pred == ICmpInst::ICMP_EQ)
+      CR = IsAnd ? EqCR.inverse() : EqCR;
+    else
+      CR = IsAnd ? EqCR : EqCR.inverse();
+    return true;
+  };
+
+  Value *Base1 = nullptr, *Base2 = nullptr;
+  ConstantRange CR1(C1->getBitWidth(), /*isFullSet=*/true);
+  ConstantRange CR2(C2->getBitWidth(), /*isFullSet=*/true);
+  const APInt *Offset1 = nullptr, *Offset2 = nullptr;
+
+  bool OK1 = getRangeForMaskedICmp(Pred1, V1, *C1, Base1, CR1);
+  if (!OK1)
+    OK1 = getRangeForICmp(Pred1, V1, *C1, Base1, CR1, Offset1);
+
+  bool OK2 = getRangeForMaskedICmp(Pred2, V2, *C2, Base2, CR2);
+  if (!OK2)
+    OK2 = getRangeForICmp(Pred2, V2, *C2, Base2, CR2, Offset2);
+
+  if (!OK1 || !OK2 || Base1 != Base2)
+    return nullptr;
+
+  Type *Ty = Base1->getType();
+  Value *NewV = Base1;
   std::optional<ConstantRange> CR = CR1.exactUnionWith(CR2);
   if (!CR) {
     if (!(ICmp1->hasOneUse() && ICmp2->hasOneUse()) || CR1.isWrappedSet() ||
@@ -1384,6 +1430,7 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   return Builder.CreateICmp(NewPred, NewV, ConstantInt::get(Ty, NewC));
 }

